mapper.select:
SELECT FCLTS_CODE, UNIT_CODE, HDQRTRS_CODE, SN_CODE, TAG_NM, BRFFC_CODE, TAG_USE_YN, FCLT_ID, FCLT_DTL_ID, DATA_PRCS_MTHD, TAGSN, BPLC_CODE, TAG_RULE_ID, HEDOFC_TRNSMIS_YN, TAG_CLS, TAG_ADIT_DC, PROCS_CODE, FNCT_CODE, PROCS_ID, VRNT_CODE, TAGSN_LOG, NVL(IS_REVISN, 'N') AS IS_REVISN FROM RDITAG_TB T LEFT JOIN ( SELECT DISTINCT TAGSN AS TAGSN_LOG, 'Y' AS IS_REVISN FROM RDIREVISNLOG_TB WHERE REPLACE(REPLACE(REPLACE(#{from_dt}, '-', ''), ' ', ''), ':', '') <= DATA_SAVE_DT AND DATA_SAVE_DT <= REPLACE(REPLACE(REPLACE(#{to_dt}, '-', ''), ' ', ''), ':', '')
AND REVISN_REMARK = #{dest}
) L ON T.TAGSN = L.TAGSN_LOG WHERE 1 = 1
AND IS_REVISN = 'Y'
AND PROCS_ID = #{procs_id}
AND TAG_NM LIKE '%' || #{searchwd} || '%'
AND FCLT_ID = #{fclt_id}
AND FCLT_DTL_ID = #{fclt_dtl_id}
ORDER BY TAGSN
